mapper.select:
SELECT COUNT(1) AS totalOrders, COALESCE(SUM(order_info.pay_amount), 0) AS grossSales, COALESCE(SUM(order_info.profit_amount), 0) AS grossProfit, COALESCE(SUM(refund.refundAmount), 0) AS refundAmount, COALESCE(SUM(refund.profitReduction), 0) AS profitReduction FROM order_info order_info LEFT JOIN ( SELECT order_refund.orderId, SUM(order_refund.refundAmount) AS refundAmount, SUM(order_refund.profitReduction) AS profitReduction FROM ( SELECT aftersale.id AS aftersaleId, aftersale.order_id AS orderId, aftersale.approved_amount AS refundAmount, COALESCE( SUM( CASE WHEN apply_total.totalApplyAmount IS NULL OR apply_total.totalApplyAmount = 0 THEN 0 ELSE aftersale.approved_amount * aftersale_item.apply_amount / apply_total.totalApplyAmount END - CASE WHEN aftersale.need_return = 1 THEN order_item.cost_price * aftersale_item.quantity ELSE 0 END ), aftersale.approved_amount ) AS profitReduction FROM aftersale_info aftersale LEFT JOIN ( SELECT aftersale_id, SUM(apply_amount) AS totalApplyAmount FROM aftersale_item GROUP BY aftersale_id ) apply_total ON apply_total.aftersale_id = aftersale.id LEFT JOIN aftersale_item aftersale_item ON aftersale_item.aftersale_id = aftersale.id LEFT JOIN order_item order_item ON order_item.id = aftersale_item.order_item_id WHERE aftersale.deleted = 0 AND aftersale.aftersale_status = 'FINISHED' GROUP BY aftersale.id, aftersale.order_id, aftersale.approved_amount ) order_refund GROUP BY order_refund.orderId ) refund ON refund.orderId = order_info.id WHERE order_info.deleted = 0 AND order_info.merchant_id = #{merchantId}
AND order_info.created_time >= #{startTime}
AND order_info.created_time < #{endTime}

SELECT CAST(order_info.customer_id AS CHAR) AS id, customer.company_name AS customerName, COUNT(1) AS orderCount, COALESCE(SUM(order_info.pay_amount), 0) AS grossAmount, COALESCE(SUM(refund.refundAmount), 0) AS refundAmount, COALESCE(SUM(order_info.pay_amount), 0) - COALESCE(SUM(refund.refundAmount), 0) AS netAmount, COALESCE(SUM(order_info.profit_amount), 0) AS grossProfit, COALESCE(SUM(order_info.profit_amount), 0) - COALESCE(SUM(refund.profitReduction), 0) AS netProfit FROM order_info order_info LEFT JOIN customer_info customer ON customer.id = order_info.customer_id AND customer.deleted = 0 LEFT JOIN ( SELECT order_refund.orderId, SUM(order_refund.refundAmount) AS refundAmount, SUM(order_refund.profitReduction) AS profitReduction FROM ( SELECT aftersale.id AS aftersaleId, aftersale.order_id AS orderId, aftersale.approved_amount AS refundAmount, COALESCE( SUM( CASE WHEN apply_total.totalApplyAmount IS NULL OR apply_total.totalApplyAmount = 0 THEN 0 ELSE aftersale.approved_amount * aftersale_item.apply_amount / apply_total.totalApplyAmount END - CASE WHEN aftersale.need_return = 1 THEN order_item.cost_price * aftersale_item.quantity ELSE 0 END ), aftersale.approved_amount ) AS profitReduction FROM aftersale_info aftersale LEFT JOIN ( SELECT aftersale_id, SUM(apply_amount) AS totalApplyAmount FROM aftersale_item GROUP BY aftersale_id ) apply_total ON apply_total.aftersale_id = aftersale.id LEFT JOIN aftersale_item aftersale_item ON aftersale_item.aftersale_id = aftersale.id LEFT JOIN order_item order_item ON order_item.id = aftersale_item.order_item_id WHERE aftersale.deleted = 0 AND aftersale.aftersale_status = 'FINISHED' GROUP BY aftersale.id, aftersale.order_id, aftersale.approved_amount ) order_refund GROUP BY order_refund.orderId ) refund ON refund.orderId = order_info.id WHERE order_info.deleted = 0 AND order_info.merchant_id = #{merchantId}
AND order_info.created_time >= #{startTime}
AND order_info.created_time < #{endTime}
GROUP BY order_info.customer_id, customer.company_name ORDER BY netAmount DESC, orderCount DESC LIMIT 10

SELECT CAST(order_item.sku_id AS CHAR) AS id, CONCAT(order_item.spu_name, ' / ', order_item.sku_name) AS productName, SUM(order_item.quantity) AS saleQty, COALESCE(SUM(order_item.final_amount), 0) AS grossAmount, COALESCE(SUM(refund.refundAmount), 0) AS refundAmount, COALESCE(SUM(order_item.final_amount), 0) - COALESCE(SUM(refund.refundAmount), 0) AS netAmount, COALESCE(SUM(order_item.profit_amount), 0) AS grossProfit, COALESCE(SUM(order_item.profit_amount), 0) - COALESCE(SUM(refund.profitReduction), 0) AS netProfit, COALESCE(SUM(refund.returnQty), 0) AS returnQty FROM order_item order_item JOIN order_info order_info ON order_info.id = order_item.order_id AND order_info.deleted = 0 LEFT JOIN ( SELECT item_refund.orderItemId, SUM(item_refund.refundAmount) AS refundAmount, SUM(item_refund.profitReduction) AS profitReduction, SUM(item_refund.returnQty) AS returnQty FROM ( SELECT aftersale_item.order_item_id AS orderItemId, CASE WHEN apply_total.totalApplyAmount IS NULL OR apply_total.totalApplyAmount = 0 THEN 0 ELSE aftersale.approved_amount * aftersale_item.apply_amount / apply_total.totalApplyAmount END AS refundAmount, ( CASE WHEN apply_total.totalApplyAmount IS NULL OR apply_total.totalApplyAmount = 0 THEN 0 ELSE aftersale.approved_amount * aftersale_item.apply_amount / apply_total.totalApplyAmount END - CASE WHEN aftersale.need_return = 1 THEN order_item.cost_price * aftersale_item.quantity ELSE 0 END ) AS profitReduction, CASE WHEN aftersale.need_return = 1 THEN aftersale_item.quantity ELSE 0 END AS returnQty FROM aftersale_info aftersale JOIN aftersale_item aftersale_item ON aftersale_item.aftersale_id = aftersale.id JOIN order_item order_item ON order_item.id = aftersale_item.order_item_id LEFT JOIN ( SELECT aftersale_id, SUM(apply_amount) AS totalApplyAmount FROM aftersale_item GROUP BY aftersale_id ) apply_total ON apply_total.aftersale_id = aftersale.id WHERE aftersale.deleted = 0 AND aftersale.aftersale_status = 'FINISHED' ) item_refund GROUP BY item_refund.orderItemId ) refund ON refund.orderItemId = order_item.id WHERE order_info.merchant_id = #{merchantId}
AND order_info.created_time >= #{startTime}
AND order_info.created_time < #{endTime}
GROUP BY order_item.sku_id, order_item.spu_name, order_item.sku_name ORDER BY netAmount DESC, saleQty DESC LIMIT 10
